import json

tool_schema = {
    "name": "calculator",
    "description": "Perform basic math operations",
    "parameters": {
        "type": "___",
        "properties": {
            "operation": {
                "type": "___",
                "description": "The math operation (add, subtract, multiply, divide)"
            },
            "numbers": {
                "type": "___",
                "items": {"type": "number"}
            }
        },
        "required": ["operation", "numbers"]
    }
}

print(json.dumps(tool_schema, indent=2))

lessons.solution:
import json

tool_schema = {
    "name": "calculator",
    "description": "Perform basic math operations",
    "parameters": {
        "type": "object",
        "properties": {
            "operation": {
                "type": "string",
                "description": "The math operation (add, subtract, multiply, divide)"
            },
            "numbers": {
                "type": "array",
                "items": {"type": "number"}
            }
        },
        "required": ["operation", "numbers"]
    }
}

print(json.dumps(tool_schema, indent=2))
